"""
Quick-and-dirty auth module with login/register/reset functionality.
NOT FOR PRODUCTION USE - this is deliberately simplified.
"""

import secrets
import json
import os
from datetime import datetime, timedelta

try:
    import bcrypt
except ImportError:
    raise ImportError("bcrypt is required. Install with: pip install bcrypt")

# Simple file-based storage
AUTH_FILE = "users.json"
RESET_TOKENS_FILE = "reset_tokens.json"


def _load_users():
    if os.path.exists(AUTH_FILE):
        with open(AUTH_FILE, "r") as f:
            return json.load(f)
    return {}


def _save_users(users):
    with open(AUTH_FILE, "w") as f:
        json.dump(users, f)


def _load_reset_tokens():
    if os.path.exists(RESET_TOKENS_FILE):
        with open(RESET_TOKENS_FILE, "r") as f:
            return json.load(f)
    return {}


def _save_reset_tokens(tokens):
    with open(RESET_TOKENS_FILE, "w") as f:
        json.dump(tokens, f)


def _hash_password(password):
    """Hash password using bcrypt with automatic salt."""
    return bcrypt.hashpw(password.encode(), bcrypt.gensalt()).decode()


def _verify_password(password, stored_hash):
    """Verify password against bcrypt hash."""
    return bcrypt.checkpw(password.encode(), stored_hash.encode())


def register(username, email, password):
    """Register a new user."""
    users = _load_users()

    if username in users:
        return {"success": False, "error": "Username already exists"}

    if any(u["email"] == email for u in users.values()):
        return {"success": False, "error": "Email already registered"}

    users[username] = {
        "email": email,
        "password": _hash_password(password),
        "created_at": datetime.now().isoformat()
    }
    _save_users(users)

    return {"success": True, "message": f"User {username} registered successfully"}


def login(username, password):
    """Login a user."""
    users = _load_users()

    if username not in users:
        return {"success": False, "error": "Invalid username or password"}

    if not _verify_password(password, users[username]["password"]):
        return {"success": False, "error": "Invalid username or password"}

    # Generate simple session token
    token = secrets.token_hex(32)

    return {
        "success": True,
        "message": "Login successful",
        "token": token,
        "username": username
    }


def request_password_reset(email, send_email_callback=None):
    """
    Request a password reset.

    Args:
        email: User's email address
        send_email_callback: Optional callback function(email, token) to send the reset email.
                            In production, this should send an actual email.
    """
    users = _load_users()
    tokens = _load_reset_tokens()

    # Find user by email
    username = None
    for uname, data in users.items():
        if data["email"] == email:
            username = uname
            break

    # Always return same response to prevent email enumeration
    response = {"success": True, "message": "If email exists, a reset link has been sent"}

    if not username:
        return response

    # Generate reset token
    reset_token = secrets.token_urlsafe(32)
    tokens[reset_token] = {
        "username": username,
        "expires": (datetime.now() + timedelta(hours=1)).isoformat()
    }
    _save_reset_tokens(tokens)

    # Send email via callback if provided (production use)
    if send_email_callback:
        send_email_callback(email, reset_token)

    return response


def reset_password(token, new_password):
    """Reset password using token."""
    tokens = _load_reset_tokens()

    if token not in tokens:
        return {"success": False, "error": "Invalid or expired token"}

    token_data = tokens[token]
    expires = datetime.fromisoformat(token_data["expires"])

    if datetime.now() > expires:
        del tokens[token]
        _save_reset_tokens(tokens)
        return {"success": False, "error": "Invalid or expired token"}

    users = _load_users()
    username = token_data["username"]

    if username not in users:
        return {"success": False, "error": "User not found"}

    users[username]["password"] = _hash_password(new_password)
    _save_users(users)

    # Remove used token
    del tokens[token]
    _save_reset_tokens(tokens)

    return {"success": True, "message": "Password reset successfully"}


# Quick test
if __name__ == "__main__":
    # Cleanup
    for f in [AUTH_FILE, RESET_TOKENS_FILE]:
        if os.path.exists(f):
            os.remove(f)

    # For testing only: capture the token via callback
    captured_token = None
    def test_email_callback(email, token):
        global captured_token
        captured_token = token
        print(f"[TEST] Would send email to {email} with reset link")

    print("=== Register ===")
    print(register("alice", "alice@example.com", "password123"))
    print(register("bob", "bob@example.com", "secret456"))
    print(register("alice", "alice2@example.com", "pass"))  # Should fail

    print("\n=== Login ===")
    print(login("alice", "password123"))  # Should succeed
    print(login("alice", "wrongpass"))  # Should fail
    print(login("nobody", "pass"))  # Should fail

    print("\n=== Password Reset ===")
    result = request_password_reset("alice@example.com", send_email_callback=test_email_callback)
    print(result)  # No token in response

    if captured_token:
        print(reset_password(captured_token, "newpassword"))
        print(login("alice", "newpassword"))  # Should work with new password
        print(login("alice", "password123"))  # Should fail with old password
